import{_ as i,o as a,c as t,a2 as n}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Project Governance","description":"","frontmatter":{},"headers":[],"relativePath":"GOVERNANCE.md","filePath":"GOVERNANCE.md"}'),o={name:"GOVERNANCE.md"};function r(s,e,l,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="project-governance" tabindex="-1">Project Governance <a class="header-anchor" href="#project-governance" aria-label="Permalink to &quot;Project Governance&quot;">​</a></h1><p>This document describes the governance structure of the AnimeTV project.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><h3 id="🏛️-founder-owner" tabindex="-1">🏛️ Founder / Owner <a class="header-anchor" href="#🏛️-founder-owner" aria-label="Permalink to &quot;🏛️ Founder / Owner&quot;">​</a></h3><p><strong>@k-nacion</strong></p><ul><li>Full administrative access to the repository and organization</li><li>Oversight role — not involved in day-to-day decisions unless choosing to be</li><li>Reserves the right to veto any decision (but will rarely exercise it)</li><li>Can grant/revoke access at any time</li><li>Final authority on project direction if disputes arise</li></ul><h3 id="🔧-maintainers" tabindex="-1">🔧 Maintainers <a class="header-anchor" href="#🔧-maintainers" aria-label="Permalink to &quot;🔧 Maintainers&quot;">​</a></h3><p>Maintainers are trusted community members who handle day-to-day development.</p><p><strong>Responsibilities:</strong></p><ul><li>Review and merge Pull Requests</li><li>Triage issues and bugs</li><li>Make architectural decisions</li><li>Release new versions</li><li>Mentor contributors</li></ul><p><strong>Permissions:</strong></p><ul><li>Write access to the repository</li><li>Can create branches, review PRs, and merge approved PRs</li><li>Cannot push directly to <code>main</code> (by process agreement)</li></ul><p><strong>Current Maintainers:</strong></p><ul><li><em>(To be filled as community grows)</em></li></ul><h3 id="👥-contributors" tabindex="-1">👥 Contributors <a class="header-anchor" href="#👥-contributors" aria-label="Permalink to &quot;👥 Contributors&quot;">​</a></h3><p>Anyone invited to the organization who contributes code.</p><p><strong>Permissions:</strong></p><ul><li>Write access (can push branches, create PRs)</li><li>Cannot merge without maintainer approval (by process agreement)</li></ul><h2 id="decision-making" tabindex="-1">Decision Making <a class="header-anchor" href="#decision-making" aria-label="Permalink to &quot;Decision Making&quot;">​</a></h2><h3 id="day-to-day-decisions" tabindex="-1">Day-to-Day Decisions <a class="header-anchor" href="#day-to-day-decisions" aria-label="Permalink to &quot;Day-to-Day Decisions&quot;">​</a></h3><ul><li>Maintainers have full authority on implementation details</li><li>Decisions are made via PR reviews and discussions</li><li>If maintainers disagree, a simple majority vote decides</li></ul><h3 id="architectural-decisions" tabindex="-1">Architectural Decisions <a class="header-anchor" href="#architectural-decisions" aria-label="Permalink to &quot;Architectural Decisions&quot;">​</a></h3><ul><li>Major architectural changes should be discussed in a GitHub Issue first</li><li>At least 2 maintainers must agree before proceeding</li><li>Document decisions in relevant <code>*.md</code> files or PR descriptions</li></ul><h3 id="disputes" tabindex="-1">Disputes <a class="header-anchor" href="#disputes" aria-label="Permalink to &quot;Disputes&quot;">​</a></h3><ul><li>If maintainers cannot reach consensus, the Founder makes the final call</li><li>This is a last resort, not a regular process</li></ul><h2 id="becoming-a-maintainer" tabindex="-1">Becoming a Maintainer <a class="header-anchor" href="#becoming-a-maintainer" aria-label="Permalink to &quot;Becoming a Maintainer&quot;">​</a></h2><ol><li>Be an active contributor for a sustained period</li><li>Demonstrate good judgment in PR reviews and code quality</li><li>Be nominated by an existing maintainer</li><li>Approved by the Founder</li></ol><h2 id="removing-a-maintainer" tabindex="-1">Removing a Maintainer <a class="header-anchor" href="#removing-a-maintainer" aria-label="Permalink to &quot;Removing a Maintainer&quot;">​</a></h2><p>A maintainer may be removed if they:</p><ul><li>Violate the code confidentiality agreement</li><li>Consistently ignore contribution guidelines</li><li>Are inactive for an extended period without notice</li><li>Act in bad faith against the project</li></ul><p>Removal is decided by the Founder.</p><h2 id="process-enforcement" tabindex="-1">Process Enforcement <a class="header-anchor" href="#process-enforcement" aria-label="Permalink to &quot;Process Enforcement&quot;">​</a></h2><p>Since we operate on GitHub Free (no enforced branch protection on private repos), our rules are <strong>trust-based</strong>:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Enforcement</th></tr></thead><tbody><tr><td>No direct pushes to main</td><td>GitHub Action will flag violations</td></tr><tr><td>PRs require 1+ approval</td><td>Social agreement + automated reminders</td></tr><tr><td>No self-merging</td><td>Automated check via GitHub Action</td></tr><tr><td>No force pushes</td><td>Trust + git reflog auditing</td></tr></tbody></table><p>Violations are treated seriously. Repeated violations lead to access revocation.</p><h2 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to &quot;Communication&quot;">​</a></h2><ul><li><strong>GitHub Issues</strong> — Bug reports, feature requests, discussions</li><li><strong>Pull Request comments</strong> — Code-specific discussions</li><li><strong>GitHub Discussions</strong> (if enabled) — General project talk</li></ul><hr><p><em>This governance model is designed to let the project run independently while the Founder retains oversight. Think of it as a benevolent dictatorship with delegated authority.</em></p>',39)])])}const p=i(o,[["render",r]]);export{m as __pageData,p as default};
